// Index for quick title-based lookup
const rulesByTitle = {}
for (const rule of livingRules) {
  rulesByTitle[rule.title.toLowerCase()] = rule
}

function getAllLivingRules() {
  return livingRules
}

function getLivingRule(id) {
  return livingRules.find(r => r.id === id) || null
}

function getLivingRuleByTitle(title) {
  return rulesByTitle[title.toLowerCase()] || null
}

function searchLivingRules(query) {
  if (!query || !query.trim()) {
    return livingRules
  }
  const q = query.toLowerCase().trim()
  return livingRules.filter(rule =>
    rule.title.toLowerCase().includes(q)
    || rule.content.toLowerCase().includes(q)
  )
}

function getAllFaq() {
  return faqEntries
}

function searchFaq(query) {
  if (!query || !query.trim()) {
    return faqEntries
  }
  const q = query.toLowerCase().trim()
  return faqEntries.filter(entry =>
    entry.question.toLowerCase().includes(q)
    || entry.answer.toLowerCase().includes(q)
  )
}

function getAllErrata() {
  return errataEntries
}

function searchErrata(query) {
  if (!query || !query.trim()) {
    return errataEntries
  }
  const q = query.toLowerCase().trim()
  return errataEntries.filter(entry =>
    entry.card.toLowerCase().includes(q)
    || entry.text.toLowerCase().includes(q)
  )
}

module.exports = {
  getAllLivingRules,
  getLivingRule,
  getLivingRuleByTitle,
  searchLivingRules,
  getAllFaq,
  searchFaq,
  getAllErrata,
  searchErrata,
}
